package com.knoxhack.echostationfall.registry;
import com.knoxhack.echostationfall.EchoStationfall; import com.knoxhack.echostationfall.progression.*; import com.knoxhack.echostationfall.world.*; import com.knoxhack.echoorbitalremnants.suit.SuitState; import java.util.*; import java.util.function.Supplier; import net.minecraft.core.BlockPos; import net.minecraft.network.chat.Component; import net.minecraft.server.level.*; import net.minecraft.world.*; import net.minecraft.world.entity.*; import net.minecraft.world.entity.player.Player; import net.minecraft.world.item.*; import net.minecraft.world.level.Level; import net.neoforged.bus.api.IEventBus; import net.neoforged.neoforge.registries.*;
public final class ModItems { public static final DeferredRegister.Items ITEMS=DeferredRegister.createItems(EchoStationfall.MODID); private static final List<DeferredItem<? extends Item>> CREATIVE=new ArrayList<>(); public static final DeferredItem<Item> STATION_ACCESS_CARD=tracked(ITEMS.registerItem("station_access_card",StationAccessCardItem::new,p->p.stacksTo(1).rarity(Rarity.UNCOMMON))); public static final DeferredItem<Item> PRESSURE_SEAL_KIT=tracked(ITEMS.registerItem("pressure_seal_kit",PressureSealKitItem::new,p->p.stacksTo(16))); public static final DeferredItem<Item> EMERGENCY_OXYGEN_PACK=tracked(ITEMS.registerItem("emergency_oxygen_pack",EmergencyOxygenPackItem::new,p->p.stacksTo(8))); public static final DeferredItem<Item> STATION_BATTERY=simple("station_battery",p->p.rarity(Rarity.UNCOMMON)); public static final DeferredItem<Item> HULL_CUTTER=simple("hull_cutter",p->p.stacksTo(1).durability(256).rarity(Rarity.UNCOMMON)); public static final DeferredItem<Item> CREW_LOG_TABLET=simple("crew_log_tablet",p->p.stacksTo(16).rarity(Rarity.UNCOMMON)); public static final DeferredItem<Item> AI_OVERRIDE_CHIP=tracked(ITEMS.registerItem("ai_override_chip",AiOverrideChipItem::new,p->p.stacksTo(1).rarity(Rarity.RARE))); public static final DeferredItem<Item> SIGNAL_PANIC_DAMPENER=tracked(ITEMS.registerItem("signal_panic_dampener",SignalPanicDampenerItem::new,p->p.stacksTo(1).durability(128).rarity(Rarity.RARE))); public static final DeferredItem<Item> STATIONFALL_BLACKBOX=simple("stationfall_blackbox",p->p.stacksTo(1).rarity(Rarity.EPIC).fireResistant()); public static final DeferredItem<Item> AI_OVERRIDE_CORE=simple("ai_override_core",p->p.stacksTo(1).rarity(Rarity.EPIC).fireResistant()); public static final DeferredItem<Item> ORBITAL_MEMORY_FRAGMENT=simple("orbital_memory_fragment",p->p.rarity(Rarity.RARE).fireResistant());
 public static final DeferredItem<Item> HOLLOW_CREWMAN_SPAWN=spawn("hollow_crewman_spawn",ModEntities.HOLLOW_CREWMAN), EVA_STALKER_SPAWN=spawn("eva_stalker_spawn",ModEntities.EVA_STALKER), MEDICAL_HUSK_SPAWN=spawn("medical_husk_spawn",ModEntities.MEDICAL_HUSK), HYDROPONIC_GROWTH_SPAWN=spawn("hydroponic_growth_spawn",ModEntities.HYDROPONIC_GROWTH), MAINTENANCE_DRONE_SPAWN=spawn("maintenance_drone_spawn",ModEntities.MAINTENANCE_DRONE), SCREAMING_SIGNAL_SPAWN=spawn("screaming_signal_spawn",ModEntities.SCREAMING_SIGNAL), STATION_MIMIC_SPAWN=spawn("station_mimic_spawn",ModEntities.STATION_MIMIC), SUIT_WITHOUT_BODY_SPAWN=spawn("suit_without_body_spawn",ModEntities.SUIT_WITHOUT_BODY), STATION_MOTHER_SPAWN=spawn("station_mother_spawn",ModEntities.STATION_MOTHER);
 static { ModBlocks.ALL_BLOCKS.forEach(b->tracked(ITEMS.registerSimpleBlockItem(b))); } private ModItems(){} public static void register(IEventBus b){ITEMS.register(b);} public static List<DeferredItem<? extends Item>> creativeItems(){return List.copyOf(CREATIVE);} private static DeferredItem<Item> simple(String n,java.util.function.UnaryOperator<Item.Properties> p){return tracked(ITEMS.registerSimpleItem(n,p));} private static DeferredItem<Item> spawn(String n,Supplier<? extends EntityType<? extends Mob>> t){return tracked(ITEMS.registerItem(n,pr->new StationSpawnItem(t,pr),p->p.stacksTo(16)));} private static <T extends Item> DeferredItem<T> tracked(DeferredItem<T> i){CREATIVE.add(i);return i;} private static void consume(Player p,InteractionHand h){if(!p.hasInfiniteMaterials())p.getItemInHand(h).shrink(1);} 
 public static final class StationAccessCardItem extends Item{public StationAccessCardItem(Properties p){super(p);} public InteractionResult use(Level l,Player p,InteractionHand h){if(l.isClientSide())return InteractionResult.SUCCESS; if(p instanceof ServerPlayer sp){if(StationfallDimensions.isStation(l)&&p.isShiftKeyDown())return StationfallRouteService.returnFromStation(sp)?InteractionResult.SUCCESS_SERVER:InteractionResult.CONSUME; return StationfallRouteService.board(sp,"access_card")?InteractionResult.SUCCESS_SERVER:InteractionResult.CONSUME;} return InteractionResult.CONSUME;}}
 public static final class PressureSealKitItem extends Item{public PressureSealKitItem(Properties p){super(p);} public InteractionResult use(Level l,Player p,InteractionHand h){if(!l.isClientSide()){SuitState s=SuitState.get(p);s.applySealantPatch();s.save(p);consume(p,h);com.knoxhack.echostationfall.integration.StationfallMissionHooks.recordPressureStabilized(p,"pressure_seal_kit");p.sendSystemMessage(Component.literal("ECHO-7 // Pressure Seal Kit applied. Hull integrity locally improved."));} return InteractionResult.SUCCESS_SERVER;}}
 public static final class EmergencyOxygenPackItem extends Item{public EmergencyOxygenPackItem(Properties p){super(p);} public InteractionResult use(Level l,Player p,InteractionHand h){if(!l.isClientSide()){SuitState s=SuitState.get(p);s.boostOxygen(60);s.save(p);consume(p,h);com.knoxhack.echostationfall.integration.StationfallMissionHooks.recordOxygenStabilized(p,"emergency_oxygen_pack");p.sendSystemMessage(Component.literal("ECHO-7 // Emergency oxygen pack vented into suit reserves."));} return InteractionResult.SUCCESS_SERVER;}}
 public static final class AiOverrideChipItem extends Item{public AiOverrideChipItem(Properties p){super(p);} public InteractionResult use(Level l,Player p,InteractionHand h){if(!l.isClientSide()){StationfallProgress.get(p).markAiOverrideObtained(p);p.sendSystemMessage(Component.literal("ECHO-7 // AI Override Chip synchronized. Station Mother will hear this."));} return InteractionResult.SUCCESS_SERVER;}}
 public static final class SignalPanicDampenerItem extends Item{public SignalPanicDampenerItem(Properties p){super(p);} public InteractionResult use(Level l,Player p,InteractionHand h){if(!l.isClientSide()){SignalPanicState s=SignalPanicState.get(p);s.decay(p,35);p.getItemInHand(h).hurtAndBreak(1,p,h);com.knoxhack.echostationfall.integration.StationfallMissionHooks.recordPanicDampened(p,"signal_panic_dampener");p.sendSystemMessage(Component.literal("ECHO-7 // Dampener pulse fired. Signal Panic reduced to "+s.value()+"%."));} return InteractionResult.SUCCESS_SERVER;}}
 public static final class StationSpawnItem extends Item{private final Supplier<? extends EntityType<? extends Mob>> type; public StationSpawnItem(Supplier<? extends EntityType<? extends Mob>> t,Properties p){super(p);type=t;} public InteractionResult use(Level l,Player p,InteractionHand h){if(l.isClientSide())return InteractionResult.SUCCESS; if(l instanceof ServerLevel sl){BlockPos pos=p.blockPosition().offset(0,1,2);Entity e=type.get().create(sl,EntitySpawnReason.SPAWN_ITEM_USE); if(e!=null){e.setPos(pos.getX()+.5,pos.getY(),pos.getZ()+.5);sl.addFreshEntity(e);consume(p,h);}} return InteractionResult.SUCCESS_SERVER;}}
}
